import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { LoginComponent } from './components/login/login.component';
import { TaskListComponent } from './components/task-list/task-list.component';
import { TaskFormComponent } from './components/task-form/task-form.component';
import { AuthGuard } from './services/auth.guard';

const routes: Routes = [
  // { path: 'logins', component: LoginComponent },
  { path: 'task-list', component: TaskListComponent, canActivate: [AuthGuard] },
  { path: 'task-form', component: TaskFormComponent, canActivate: [AuthGuard] },
  // Add other routes as needed
  //{ path: '', redirectTo: '/login', pathMatch: 'full' }, // Default redirect to login
  //{ path: '**', redirectTo: '/login' }, // Redirect to login for any unknown route];
];
@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule],
})
export class AppRoutingModule {}
